Method.Source:
/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(EcoResProductDetailsExtended, ETGCanadaProduction_ETGSFGMapping), FormControlEventType::Modified)]
public static void ETGCanadaProduction_ETGSFGMapping_OnModified(FormControl sender, FormControlEventArgs e)
{
    FormRun         formRun = sender.formRun();
    FormDataSource  inventTableDs;
    InventTable     inventTable;

    inventTableDs   = formRun.dataSource(formDataSourceStr(EcoResProductDetailsExtended, InventTable));
    inventTable     = inventTableDs.cursor();

    if(inventTable.ETGSFGMapping)
    {
        inventTableDs.object(fieldNum(InventTable, ETG_SFGQuantity)).mandatory(true);
        inventTableDs.object(fieldNum(InventTable, ETGPackagingMaterial)).mandatory(true);
    }
    else
    {
        inventTableDs.object(fieldNum(InventTable, ETG_SFGQuantity)).mandatory(false);
        inventTableDs.object(fieldNum(InventTable, ETGPackagingMaterial)).mandatory(false);
    }
}
